+func TestSanitizeMessageBody_FullSkipsTruncation(t *testing.T) {
+	long := strings.Repeat("€", 210)
+	got := sanitizeMessageBody(long, true)
+	if strings.HasSuffix(got, "...") {
+		t.Fatalf("expected no truncation with full=true, got %q", got)
+	}
